"""Parse standard 5-field cron expressions into a structured, describable schedule.

Cron format: "minute hour day_of_month month day_of_week"

The module reads top-down in four layers:

    1. Data models      -- FieldSpec, CronField, CronSchedule
    2. Field parsing    -- one shared `parse_field` used by all five fields
    3. Expression parse -- `parse_cron` ties the five fields together
    4. Description      -- `CronSchedule.describe()` and its small helpers
"""

from __future__ import annotations

from dataclasses import dataclass
from typing import Callable


# --------------------------------------------------------------------------- #
# 1. Data models
# --------------------------------------------------------------------------- #


@dataclass(frozen=True)
class FieldSpec:
    """The name and legal value range of a single cron field."""

    name: str
    min_value: int
    max_value: int


# The five fields in the order they appear in a cron expression.
FIELD_SPECS: tuple[FieldSpec, ...] = (
    FieldSpec("minute", 0, 59),
    FieldSpec("hour", 0, 23),
    FieldSpec("day_of_month", 1, 31),
    FieldSpec("month", 1, 12),
    FieldSpec("day_of_week", 0, 6),
)

MONTH_NAMES: tuple[str, ...] = (
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December",
)

DAY_NAMES: tuple[str, ...] = (
    "Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday",
)


@dataclass(frozen=True)
class CronField:
    """A parsed cron field: the original token plus every value it matches."""

    raw: str
    values: tuple[int, ...]

    @property
    def is_wildcard(self) -> bool:
        return self.raw == "*"

    @property
    def is_single(self) -> bool:
        return len(self.values) == 1

    @property
    def single_value(self) -> int:
        if not self.is_single:
            raise ValueError(f"Field {self.raw!r} does not hold a single value")
        return self.values[0]

    @property
    def is_step(self) -> bool:
        """True for tokens like ``*/15`` (every Nth value across the full range)."""
        return self.raw.startswith("*/")

    @property
    def step(self) -> int:
        return int(self.raw.split("/", 1)[1])

    @property
    def is_range(self) -> bool:
        """True for plain ranges like ``1-5`` (not lists or stepped ranges)."""
        return "-" in self.raw and "," not in self.raw and "/" not in self.raw


@dataclass(frozen=True)
class CronSchedule:
    """A fully parsed cron expression."""

    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        """Render the schedule as a human-readable English sentence."""
        parts = [self._describe_time()]
        calendar = self._describe_calendar()
        if calendar:
            parts.append(calendar)
        return " ".join(parts)

    # -- time-of-day phrasing (minute + hour) ------------------------------- #

    def _describe_time(self) -> str:
        if self.minute.is_wildcard and self.hour.is_wildcard:
            return "Every minute"
        if self.minute.is_step and self.hour.is_wildcard:
            return f"Every {self.minute.step} minutes"
        if self.hour.is_step and _is_exactly(self.minute, 0):
            return f"Every {self.hour.step} hours, on the hour"
        if self.minute.is_single and self.hour.is_single:
            return self._describe_clock_time()
        return self._describe_general_time()

    def _describe_clock_time(self) -> str:
        hour, minute = self.hour.single_value, self.minute.single_value
        if hour == 0 and minute == 0:
            return "At midnight"
        return f"At {hour:02d}:{minute:02d}"

    def _describe_general_time(self) -> str:
        minute = (
            "every minute" if self.minute.is_wildcard
            else f"minute {_describe_values(self.minute, str)}"
        )
        hour = (
            "every hour" if self.hour.is_wildcard
            else f"hour {_describe_values(self.hour, str)}"
        )
        return f"At {minute} past {hour}"

    # -- calendar phrasing (day-of-month, month, day-of-week) --------------- #

    def _describe_calendar(self) -> str:
        clauses: list[str] = []
        if not self.day_of_month.is_wildcard:
            clauses.append(self._describe_day_of_month())
        elif not self.month.is_wildcard:
            clauses.append(f"in {self._describe_month()}")
        if not self.day_of_week.is_wildcard:
            clauses.append(f"on {self._describe_day_of_week()}")
        return " ".join(clauses)

    def _describe_day_of_month(self) -> str:
        days = _describe_values(self.day_of_month, _ordinal)
        month = "every month" if self.month.is_wildcard else self._describe_month()
        return f"on the {days} of {month}"

    def _describe_month(self) -> str:
        return _describe_values(self.month, lambda n: MONTH_NAMES[n - 1])

    def _describe_day_of_week(self) -> str:
        return _describe_values(self.day_of_week, lambda n: DAY_NAMES[n])


# --------------------------------------------------------------------------- #
# 2. Field parsing  --  shared by all five fields
# --------------------------------------------------------------------------- #


def parse_field(token: str, spec: FieldSpec) -> CronField:
    """Parse one cron field, handling wildcards, ranges, lists, and steps."""
    if not token:
        raise ValueError(f"Empty {spec.name} field")

    values: set[int] = set()
    for part in token.split(","):
        values.update(_parse_part(part, spec))

    return CronField(raw=token, values=tuple(sorted(values)))


def _parse_part(part: str, spec: FieldSpec) -> range:
    """Parse a single comma-separated component, e.g. ``*``, ``5``, ``1-30/5``."""
    range_spec, _, step_spec = part.partition("/")
    step = _parse_step(step_spec, part) if step_spec else 1
    low, high = _parse_range(range_spec, spec)
    return range(low, high + 1, step)


def _parse_range(range_spec: str, spec: FieldSpec) -> tuple[int, int]:
    """Resolve ``*``, a single value, or ``low-high`` into inclusive bounds."""
    if range_spec == "*":
        return spec.min_value, spec.max_value

    if "-" in range_spec:
        low_text, high_text = range_spec.split("-", 1)
        low, high = _parse_int(low_text, spec), _parse_int(high_text, spec)
        if low > high:
            raise ValueError(
                f"Invalid {spec.name} range {range_spec!r}: start exceeds end"
            )
        return low, high

    value = _parse_int(range_spec, spec)
    return value, value


def _parse_step(step_spec: str, part: str) -> int:
    step = _parse_int(step_spec, spec=None)  # a step is a count, not a field value
    if step < 1:
        raise ValueError(f"Step must be 1 or greater in {part!r}")
    return step


def _parse_int(text: str, spec: FieldSpec | None) -> int:
    """Convert a token to an int, enforcing the field's range when one is given."""
    try:
        value = int(text)
    except ValueError:
        raise ValueError(f"Expected an integer but got {text!r}") from None

    if spec is not None and not (spec.min_value <= value <= spec.max_value):
        raise ValueError(
            f"{spec.name} value {value} out of range "
            f"[{spec.min_value}, {spec.max_value}]"
        )
    return value


# --------------------------------------------------------------------------- #
# 3. Expression parsing
# --------------------------------------------------------------------------- #


def parse_cron(expression: str) -> CronSchedule:
    """Parse a full 5-field cron expression into a :class:`CronSchedule`."""
    tokens = expression.split()
    if len(tokens) != 5:
        raise ValueError(
            f"Expected 5 fields (minute hour day_of_month month day_of_week), "
            f"got {len(tokens)}: {expression!r}"
        )

    fields = [parse_field(token, spec) for token, spec in zip(tokens, FIELD_SPECS)]
    return CronSchedule(*fields)


# --------------------------------------------------------------------------- #
# 4. Description helpers (pure formatting, no cron knowledge)
# --------------------------------------------------------------------------- #


def _is_exactly(field: CronField, value: int) -> bool:
    return field.is_single and field.single_value == value


def _describe_values(field: CronField, name_of: Callable[[int], str]) -> str:
    """Describe a field's values as a range ("A through B") or an English list."""
    if field.is_range:
        low, high = field.values[0], field.values[-1]
        return f"{name_of(low)} through {name_of(high)}"
    return _join_human([name_of(value) for value in field.values])


def _join_human(items: list[str]) -> str:
    """Join items with Oxford-comma English grammar."""
    if len(items) == 1:
        return items[0]
    if len(items) == 2:
        return f"{items[0]} and {items[1]}"
    return ", ".join(items[:-1]) + f", and {items[-1]}"


def _ordinal(n: int) -> str:
    """Format an integer as an ordinal: 1 -> '1st', 22 -> '22nd', 13 -> '13th'."""
    if 11 <= (n % 100) <= 13:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(n % 10, "th")
    return f"{n}{suffix}"


# --------------------------------------------------------------------------- #
# Demo
# --------------------------------------------------------------------------- #

if __name__ == "__main__":
    EXAMPLES = [
        "* * * * *",
        "0 12 * * 1-5",
        "*/15 * * * *",
        "0 0 1 * *",
        "30 8 * * 1,3,5",
        "0 */2 * * *",
    ]
    for expr in EXAMPLES:
        print(f"{expr:<16} -> {parse_cron(expr).describe()}")
```

## How it's decomposed

The code is organized into four layers that read top-to-bottom, so you never have to jump backward to follow the flow:

**1. Data models.** `FieldSpec` declares each field's legal range in one table (`FIELD_SPECS`) — the single source of truth that drives both validation and the `*` wildcard bounds. `CronField` holds a field's `raw` token *and* its expanded `values`, exposing readable predicates (`is_wildcard`, `is_single`, `is_step`, `is_range`) so the description layer asks intent questions instead of re-parsing strings. `CronSchedule` is the structured result.

**2. One shared field parser.** All five fields go through `parse_field`, which splits on commas and delegates each part to `_parse_part` → `_parse_range` / `_parse_step` / `_parse_int`. Every form (`*`, `42`, `1-5`, `1,3,5`, `*/15`, `1-30/5`) is handled here once — no per-field duplication. The whole expansion reduces to building a `range(low, high + 1, step)`.

**3. Expression parsing.** `parse_cron` just zips tokens with `FIELD_SPECS` and validates the field count.

**4. Description.** `describe()` composes a *time* phrase (`_describe_time`) with a *calendar* phrase (`_describe_calendar`). Pure formatting helpers (`_join_human` for Oxford commas, `_ordinal`, `_describe_values`) know nothing about cron, so they're trivially reusable and testable.

## Validation

Clear `ValueError`s for: wrong field count, non-integers, out-of-range values (e.g. minute 60), inverted ranges (`5-2`), and steps below 1.

One deliberate design note: I keep each field's original `raw` token alongside its expanded `values`. The expanded set drives correctness; the raw token lets `describe()` choose natural phrasing ("Every 15 minutes" vs. listing 0, 15, 30, 45) without re-parsing.

