            self.day_of_month,
            self.month,
            self.day_of_week,
        )

        if date_parts:
            return f"{time_text} {date_parts}"

        return time_text

    def _is_every_minute(self) -> bool:
        return all(
            field.is_wildcard()
            for field in (
                self.minute,
                self.hour,
                self.day_of_month,
                self.month,
                self.day_of_week,
            )
        )

    def _is_simple_minute_step(self) -> bool:
        return (
            is_wildcard_step(self.minute.raw)
            and self.hour.is_wildcard()
            and self.day_of_month.is_wildcard()
            and self.month.is_wildcard()
            and self.day_of_week.is_wildcard()
        )

    def _is_simple_hour_step_on_the_hour(self) -> bool:
        return (
            self.minute.values == (0,)
            and is_wildcard_step(self.hour.raw)
            and self.day_of_month.is_wildcard()
            and self.month.is_wildcard()
            and self.day_of_week.is_wildcard()
        )


