        hour=fields[1],
        day_of_month=fields[2],
        month=fields[3],
        day_of_week=fields[4],
    )


def parse_field(raw: str, name: str, min_value: int, max_value: int) -> CronField:
    values: set[int] = set()

    for item in raw.split(","):
        if not item:
            raise CronParseError(f"{name}: empty list item in {raw!r}")

