        raw=raw,
        min_value=min_value,
        max_value=max_value,
        values=tuple(sorted(values)),
    )


def parse_field_item(
    item: str,
    name: str,
    min_value: int,
    max_value: int,
) -> set[int]:
    base, step = split_step(item, name)
    start, end = parse_base_range(base, name, min_value, max_value)

    if step <= 0:
        raise CronParseError(f"{name}: step must be positive in {item!r}")

    return set(range(start, end + 1, step))


def split_step(item: str, name: str) -> tuple[str, int]:
    if "/" not in item:
        return item, 1

    pieces = item.split("/")

    if len(pieces) != 2 or not pieces[0] or not pieces[1]:
        raise CronParseError(f"{name}: invalid step syntax {item!r}")

    return pieces[0], parse_int(pieces[1], name, item)


def parse_base_range(
    base: str,
    name: str,
    min_value: int,
    max_value: int,
) -> tuple[int, int]:
    if base == "*":
        return min_value, max_value

    if "-" in base:
        pieces = base.split("-")

        if len(pieces) != 2 or not pieces[0] or not pieces[1]:
            raise CronParseError(f"{name}: invalid range syntax {base!r}")

        start = parse_int(pieces[0], name, base)
        end = parse_int(pieces[1], name, base)

        validate_value(start, name, min_value, max_value)
        validate_value(end, name, min_value, max_value)

        if start > end:
            raise CronParseError(f"{name}: range start exceeds end in {base!r}")

        return start, end

    value = parse_int(base, name, base)
    validate_value(value, name, min_value, max_value)
    return value, value


