    if not value.isdigit():
        raise CronParseError(f"{name}: expected integer in {context!r}")

    return int(value)


def validate_value(value: int, name: str, min_value: int, max_value: int) -> None:
    if value < min_value or value > max_value:
        raise CronParseError(
            f"{name}: value {value} out of range {min_value}-{max_value}"
