    return format_names(day_of_week.values, DAY_NAMES)


def is_plain_range(raw: str) -> bool:
    return "-" in raw and "," not in raw and "/" not in raw


def is_wildcard_step(raw: str) -> bool:
    return raw.startswith("*/") and raw.count("/") == 1


def extract_step(raw: str) -> int:
    return int(raw.split("/", 1)[1])


